{
  "salient_facts": [
    {
      "fact_id": "F1",
      "text": "Caroline is preparing to adopt and wants to provide a safe, loving home for children in need.",
      "category": "plan",
      "importance": "high"
    },
    {
      "fact_id": "F2",
      "text": "Melanie has a friend who recently completed the adoption process and is now happy with their child.",
      "category": "event",
      "importance": "medium"
    },
    {
      "fact_id": "F3",
      "text": "Melanie had a setback last month and had to take a break from pottery.",
      "category": "event",
      "importance": "high"
    },
    {
      "fact_id": "F4",
      "text": "Melanie is using reading and painting as creative outlets during her break from pottery.",
      "category": "state_change",
      "importance": "medium"
    },
    {
      "fact_id": "F5",
      "text": "Caroline recently attended a transgender poetry reading and found it powerful and empowering.",
      "category": "event",
      "importance": "high"
    },
    {
      "fact_id": "F6",
      "text": "Caroline created a piece of art inspired by the poetry reading, representing freedom and being real.",
      "category": "event",
      "importance": "high"
    },
    {
      "fact_id": "F7",
      "text": "Melanie admires Caroline's art and agrees that showing true self is important.",
      "category": "relationship",
      "importance": "medium"
    },
    {
      "fact_id": "F8",
      "text": "Both Caroline and Melanie value self-expression and creativity as a means of emotional release and connection.",
      "category": "preference",
      "importance": "high"
    }
  ],
  "summary": "Caroline is preparing for adoption and shares her excitement and plans with Melanie. Melanie is considering adoption after her friend's experience and is dealing with a setback that led her to take a break from pottery. She is using reading and painting as alternatives. Caroline recently attended a transgender poetry reading, which inspired her to create art representing freedom and authenticity. Melanie appreciates Caroline's art and agrees on the importance of self-expression."
}

